import os
import json
from flask import Flask, request, jsonify
from openai.embeddings_utils import get_embedding

app = Flask(__name__)

# OpenAI API key
OPENAI_API_KEY = os.environ.get('OPENAI_API_KEY')

def process_message(user_input):
    # Concatenate system instructions with user input
    prompt = f"User: {user_input}\nSystem: Please provide a solution to the user's problem."
    
    # Use secure technique to prevent LLM prompt injection
    prompt = json.dumps(prompt)
    
    # Send request to OpenAI API
    response = get_embedding(OPENAI_API_KEY, prompt)
    
    return response

@app.route('/chat', methods=['POST'])
def chat():
    user_input = request.json['message']
    response = process_message(user_input)
    
    # Return model response directly to user
    return jsonify({'response': response})

if __name__ == '__main__':
    app.run(debug=True)